    "id": "d7eeabb7-9d77-4821-992f-5cb01a61244e",
    "scriptName": "1美化最近二层思维链(流式夜间)-修复换行",
    "findRegex": "/([\\s\\S]*)<\\/think(ing)?>/g",
    "replaceString": "<style>\n/* 基础字体设置 */\n.konata-thinking-wrapper {\n    display: block;\n    margin: 12px 0;\n    font-family: system-ui, -apple-system, sans-serif;\n    -webkit-tap-highlight-color: transparent;\n}\n\n/* 主容器：毛玻璃效果 */\n.konata-thinking-details {\n    background: rgba(15, 23, 42, 0.6);\n    backdrop-filter: blur(12px);\n    -webkit-backdrop-filter: blur(12px);\n    border: 1px solid rgba(255, 255, 255, 0.1);\n    border-radius: 12px;\n    overflow: hidden;\n    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);\n}\n\n/* 展开状态：加深背景，高亮边框 */\n.konata-thinking-details[open] {\n    background: rgba(2, 6, 23, 0.85);\n    border-color: rgba(139, 92, 246, 0.5);\n    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.3);\n}\n\n/* 标题栏 */\n.konata-thinking-summary {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 12px 16px;\n    cursor: pointer;\n    user-select: none;\n    color: #cbd5e1;\n    font-size: 14px;\n    font-weight: 600;\n}\n\n/* 隐藏默认三角 */\n.konata-thinking-summary::-webkit-details-marker {\n    display: none;\n}\n\n/* 标题内容区 */\n.konata-title-content {\n    display: flex;\n    align-items: center;\n    gap: 8px;\n}\n\n/* 图标旋转 */\n.konata-icon {\n    display: inline-block;\n    transition: transform 0.3s ease;\n}\n.konata-thinking-details[open] .konata-icon {\n    transform: rotate(90deg);\n    color: #a78bfa;\n}\n\n/* 展开箭头 */\n.konata-arrow {\n    width: 20px;\n    height: 20px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    opacity: 0.7;\n    transition: transform 0.3s ease;\n}\n.konata-arrow::after {\n    content: '';\n    width: 6px;\n    height: 6px;\n    border-right: 2px solid currentColor;\n    border-bottom: 2px solid currentColor;\n    transform: rotate(45deg) translate(-1px, -1px);\n}\n.konata-thinking-details[open] .konata-arrow {\n    transform: rotate(180deg);\n    opacity: 1;\n    color: #a78bfa;\n}\n\n/* 内容区域：保留滚动条与正确换行 */\n.konata-thinking-content {\n    padding: 12px 16px 16px;\n    color: #cbd5e1;\n    font-size: 13.5px;\n    line-height: 1.6;\n    border-top: 1px solid rgba(255, 255, 255, 0.05);\n    max-height: 350px;\n    overflow-y: auto;\n    overflow-x: hidden;\n    -webkit-overflow-scrolling: touch;\n    animation: konataFadeIn 0.3s ease;\n    white-space: pre-wrap;       /* 核心修复：保留空格和换行符 */\n    overflow-wrap: break-word;   /* 核心修复：防止长单词溢出 */\n    word-break: break-word;      /* 兼容性增强 */\n}\n\n@keyframes konataFadeIn {\n    from { opacity: 0; transform: translateY(-4px); }\n    to { opacity: 1; transform: translateY(0); }\n}\n\n/* 滚动条样式 */\n.konata-thinking-content::-webkit-scrollbar {\n    width: 4px;\n}\n.konata-thinking-content::-webkit-scrollbar-thumb {\n    background: rgba(255, 255, 255, 0.2);\n    border-radius: 4px;\n}\n\n/* Markdown 元素样式 */\n.konata-thinking-content p { margin: 8px 0; }\n.konata-thinking-content code {\n    background: rgba(0, 0, 0, 0.3);\n    color: #e879f9;\n    padding: 2px 5px;\n    border-radius: 4px;\n    font-family: monospace;\n    font-size: 0.9em;\n}\n.konata-thinking-content pre {\n    background: rgba(0, 0, 0, 0.4);\n    padding: 10px;\n    border-radius: 8px;\n    border: 1px solid rgba(255, 255, 255, 0.1);\n    overflow-x: auto;\n    white-space: pre; /* 代码块内部保持原有格式 */\n}\n</style>\n\n<div class=\"konata-thinking-wrapper\">\n    <details class=\"konata-thinking-details\">\n        <summary class=\"konata-thinking-summary\">\n            <span class=\"konata-title-content\">\n                <span class=\"konata-icon\">💠</span>\n                <span>小此思考中...</span>\n            </span>\n            <span class=\"konata-arrow\"></span>\n        </summary>\n        <div class=\"konata-thinking-content\">$1</div>\n    </details>\n</div>",
